Node makeTreeR(int[] a, int start, int end) {
  if (start > end) return null;
  int mid = (start + end) / 2;
  Node node = new Node(a[mid]);
  node.left = makeTreeR(a, start, mid - 1);
  node.right = makeTreeR(a, mid + 1, end);
  return node;
